import logging
import os

class FilePathContext:
    def __init__(self, path):
        self.filepath = path if isinstance(path, str) else path.filepath
    def open(self, mode):
        return open(self.filepath, mode)

def resolve_format(fmt, filepath):
    _, ext = os.path.splitext(filepath.lower())
    if ext in ['.tsv', '.txt']:
        return 'tsv'
    if ext in ['.yaml', '.yml']:
        return 'yaml'
    return None

def parse_exchange_table_file(f):
    header = f.readline()
    for line in f:
        parts = line.strip().split('\t')
        if len(parts) != 3:
            continue
        compound = parts[0]
        try:
            lower = float(parts[1])
            upper = float(parts[2])
        except ValueError as e:
            raise ParseError(f"Non-numeric bound for compound '{compound}': {e}")
        if lower > upper:
            raise ParseError(f"Lower bound {lower} is greater than upper bound {upper} for compound '{compound}'")
        yield {'compound': compound, 'lower': lower, 'upper': upper}

def parse_exchange_yaml_file(context, f, default_compartment):
    for line in f:
        parts = line.strip().split(':')
        if len(parts) < 3:
            continue
        compound = parts[0]
        try:
            lower = float(parts[1])
            upper = float(parts[2])
        except ValueError as e:
            raise ParseError(f"Non-numeric bound for compound '{compound}': {e}")
        if lower > upper:
            raise ParseError(f"Lower bound {lower} is greater than upper bound {upper} for compound '{compound}'")
        compartment = parts[3] if len(parts) > 3 else default_compartment
        yield {'compound': compound, 'lower': lower, 'upper': upper, 'compartment': compartment}

class ParseError(Exception):
    pass

logger = logging.getLogger(__name__)

def parse_exchange_file(path, default_compartment):
    context = FilePathContext(path)
    format = resolve_format(None, context.filepath)
    if format is None:
        # content-based detection
        with context.open('r') as f:
            first_line = f.readline().strip()
            if '\t' in first_line:
                format = 'tsv'
            elif ':' in first_line:
                format = 'yaml'
            else:
                raise ParseError(f"Unable to detect format of exchange file {context.filepath}")
    if format == 'tsv':
        logger.debug(f"Parsing exchange file {context.filepath} as TSV")
        with context.open('r') as f:
            for entry in parse_exchange_table_file(f):
                yield entry
    elif format == 'yaml':
        logger.debug(f"Parsing exchange file {context.filepath} as YAML")
        with context.open('r') as f:
            for entry in parse_exchange_yaml_file(context, f, default_compartment):
                yield entry
    else:
        raise ParseError(f"Unable to detect format of exchange file {context.filepath}")

def main():
    tsv_path = 'exchange_limits.tsv'
    with open(tsv_path, 'w') as f:
        f.write('compound\tlower\tupper\n')
        f.write('Glucose\t-10\t100\n')
        f.write('Lactate\t0\t50\n')

    print('Parsing TSV file:')
    for entry in parse_exchange_file(tsv_path, default_compartment='c'):
        print(entry)

    yaml_path = 'exchange_limits.yaml'
    with open(yaml_path, 'w') as f:
        f.write('Glucose:-10:100:cytosol\n')
        f.write('O2:-1000:1000:mitochondria\n')

    print('\nParsing YAML file:')
    for entry in parse_exchange_file(yaml_path, default_compartment='c'):
        print(entry)

if __name__ == '__main__':
    main()
